#include <bits/stdc++.h>using namespace std;typedef long long ll;ll gcd(ll a,ll b){    if(b==0)return a;    return gcd(b,a%b);}ll lcm(ll a,ll b){    return (a*b)/gcd(a,b);}int main() {    ll t;    cin>>t;    while(t--){        ll a,b,c,m;        cin>>a>>b>>c>>m;        ll ab=lcm(a,b);        ll ac=lcm(a,c);        ll bc=lcm(b,c);        ll abc=lcm(ab,c);        ll aans=((m/a)*6)-((m/ab)*3)-((m/ac)*3)+((m/abc)*2);        ll bans=((m/b)*6)-((m/ab)*3)-((m/bc)*3)+((m/abc)*2);        ll cans=((m/c)*6)-((m/ac)*3)-((m/bc)*3)+((m/abc)*2);        cout<<aans<<" "<<bans<<" "<<cans<<endl;    }}